const fs = require('fs');
const body = $input.first().json.body || $input.first().json;
const jd = body.jd;

if (!jd || typeof jd !== 'string' || jd.trim().length === 0) {
  throw new Error('Missing or empty jd field in request body');
}

$workflow.staticData.retryCount = 0;
$workflow.staticData.pageRetryCount = 0;
$workflow.staticData.retryReason = null;

const resume = JSON.parse(fs.readFileSync('/app/data/master_resume.json', 'utf-8'));
const extractPrompt = fs.readFileSync('/app/prompts/extract_metadata.md', 'utf-8');
const tailorPrompt = fs.readFileSync('/app/prompts/tailor_system.md', 'utf-8');
const htmlTemplate = fs.readFileSync('/app/templates/resume.html', 'utf-8');

return [{ json: { jd: jd.trim(), resume, extractPrompt, tailorPrompt, htmlTemplate } }];

const { jd, resume, extractPrompt, tailorPrompt, htmlTemplate } = $input.first().json;

const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 300,
  system: extractPrompt,
  messages: [{ role: 'user', content: jd }]
});

return [{ json: { requestBody, jd, resume, tailorPrompt, htmlTemplate } }];

const resp = $input.first().json;
const text = resp.content[0].text.trim();

let meta;
try {
  const match = text.match(/\{[\s\S]*\}/);
  meta = JSON.parse(match ? match[0] : text);
} catch (e) {
  throw new Error('Metadata extraction returned invalid JSON: ' + text.substring(0, 200));
}

const base = $('Build Extract Request').first().json;
const retryReason = $workflow.staticData.retryReason || null;

let userMsg = `MASTER RESUME:\n${JSON.stringify(base.resume, null, 2)}\n\nJOB DESCRIPTION:\n${base.jd}`;
if (retryReason) {
  userMsg += `\n\nREVISION REQUIRED: ${retryReason}`;
}

const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 4096,
  system: base.tailorPrompt,
  messages: [{ role: 'user', content: userMsg }]
});

return [{ json: { requestBody, meta, jd: base.jd, resume: base.resume, tailorPrompt: base.tailorPrompt, htmlTemplate: base.htmlTemplate } }];

const resp = $input.first().json;
const text = resp.content[0].text.trim();

let tailored;
try {
  const match = text.match(/\{[\s\S]*\}/);
  tailored = JSON.parse(match ? match[0] : text);
} catch (e) {
  throw new Error('Tailoring returned invalid JSON: ' + text.substring(0, 200));
}

const SUMMARY_LIMIT = 280;
const BULLET_CEIL = 220;
const BULLET_FLOOR = 150;
const PROJECT_LIMIT = 180;

const errors = [];

if (!tailored.summary || tailored.summary.length > SUMMARY_LIMIT) {
  errors.push(`Summary too long (${tailored.summary?.length ?? 0} chars, limit ${SUMMARY_LIMIT})`);
}
if (!Array.isArray(tailored.tech_stack) || tailored.tech_stack.length < 8 || tailored.tech_stack.length > 12) {
  errors.push(`tech_stack must have 8-12 items (got ${tailored.tech_stack?.length ?? 0})`);
}
for (const job of (tailored.experience || [])) {
  for (const bullet of (job.bullets || [])) {
    if (bullet.length > BULLET_CEIL) {
      errors.push(`Bullet too long in ${job.company} (${bullet.length} chars, ceiling ${BULLET_CEIL})`);
    } else if (bullet.length < BULLET_FLOOR) {
      errors.push(`Bullet too short in ${job.company} (${bullet.length} chars, floor ${BULLET_FLOOR})`);
    }
  }
}
for (const proj of (tailored.projects || [])) {
  if (proj.description && proj.description.length > PROJECT_LIMIT) {
    errors.push(`Project "${proj.name}" description too long (${proj.description.length} chars)`);
  }
}
if (tailored.projects && tailored.projects.length > 2) {
  tailored.projects = tailored.projects.slice(0, 2);
}

const needsRetry = errors.length > 0;
const retryCount = $workflow.staticData.retryCount || 0;

if (needsRetry) {
  $workflow.staticData.retryReason = `Previous response exceeded limits: ${errors.join('; ')}. Compress while preserving all hard numbers and tools. Bullets must be ${BULLET_FLOOR}-${BULLET_CEIL} chars each.`;
}

const base = $('Parse Metadata').first().json;

return [{ json: {
  tailored, needsRetry, retryCount, errors,
  jd: base.jd,
  resume: base.resume,
  tailorPrompt: base.tailorPrompt,
  htmlTemplate: base.htmlTemplate,
  meta: base.meta
} }];

$workflow.staticData.retryCount = ($workflow.staticData.retryCount || 0) + 1;
const retryReason = $workflow.staticData.retryReason;
const base = $('Parse Metadata').first().json;

const userMsg = `MASTER RESUME:\n${JSON.stringify(base.resume, null, 2)}\n\nJOB DESCRIPTION:\n${base.jd}\n\nREVISION REQUIRED: ${retryReason}`;

const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 4096,
  system: base.tailorPrompt,
  messages: [{ role: 'user', content: userMsg }]
});

return [{ json: { requestBody } }];

const { tailored, htmlTemplate } = $input.first().json;
const resume = $('Load and Validate').first().json.resume;

let expHtml = '';
for (const job of tailored.experience) {
  const bullets = (job.bullets || []).map(b => `<li>${b}</li>`).join('\n        ');
  expHtml += `\n  <div class="job">\n    <div class="job-header">\n      <div>\n        <span class="job-title">${job.title}</span> &mdash;\n        <span class="job-company">${job.company}</span>\n        <span class="job-location">&nbsp;&middot;&nbsp;${job.location}</span>\n      </div>\n      <div class="job-dates">${job.start} &ndash; ${job.end}</div>\n    </div>\n    <ul class="bullets">\n        ${bullets}\n    </ul>\n  </div>`;
}

let projHtml = '';
for (const proj of (tailored.projects || []).slice(0, 2)) {
  projHtml += `\n  <div class="project">\n    <span class="project-name">${proj.name}</span>\n    <span class="project-desc"> &mdash; ${proj.description}</span>\n  </div>`;
}

let eduHtml = '';
for (const edu of resume.education) {
  eduHtml += `\n  <div class="edu-row">\n    <div>\n      <div class="edu-school">${edu.school}</div>\n      <div class="edu-degree">${edu.degree}</div>\n    </div>\n    <div class="edu-meta">${edu.date}<br>GPA: ${edu.gpa}</div>\n  </div>`;
}

let html = htmlTemplate;
html = html.replace('{{name}}', resume.name);
html = html.replace('{{email}}', resume.contact.email);
html = html.replace('{{phone}}', resume.contact.phone);
html = html.replace('{{location}}', resume.contact.location);
html = html.replace('{{linkedin}}', resume.contact.linkedin);
html = html.replace('{{github}}', resume.contact.github);
html = html.replace('{{summary}}', tailored.summary);
html = html.replace('{{tech_stack}}', tailored.tech_stack.join(' &middot; '));
html = html.replace('{{experience}}', expHtml);
html = html.replace('{{projects}}', projHtml);
html = html.replace('{{education}}', eduHtml);

return [{ json: { tailored, renderedHtml: html } }];

const { tailored, renderedHtml } = $input.first().json;
const base64 = Buffer.from(renderedHtml, 'utf-8').toString('base64');

return [{
  json: { tailored },
  binary: {
    htmlFile: {
      data: base64,
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];

const { PDFDocument } = require('pdf-lib');

const pdfBin = $input.first().binary.pdfData;
if (!pdfBin) throw new Error('No PDF data received from Gotenberg');

const pdfBytes = Buffer.from(pdfBin.data, 'base64');
const pdfDoc = await PDFDocument.load(pdfBytes);
const pageCount = pdfDoc.getPageCount();

const tailored = $('HTML to Binary').first().json.tailored;
const pageRetryCount = $workflow.staticData.pageRetryCount || 0;
const tooLong = pageCount > 1;

if (tooLong) {
  $workflow.staticData.retryReason = `PDF is ${pageCount} pages. Compress all bullets to 150-160 chars max. Summary under 200 chars. Reduce tech stack to exactly 8 items.`;
  $workflow.staticData.retryCount = 0;
}

return [{ json: { pageCount, tooLong, pageRetryCount, tailored, pdfBase64: pdfBin.data } }];

$workflow.staticData.pageRetryCount = ($workflow.staticData.pageRetryCount || 0) + 1;
const retryReason = $workflow.staticData.retryReason;
const base = $('Parse Metadata').first().json;

const userMsg = `MASTER RESUME:\n${JSON.stringify(base.resume, null, 2)}\n\nJOB DESCRIPTION:\n${base.jd}\n\nREVISION REQUIRED: ${retryReason}`;

const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 4096,
  system: base.tailorPrompt,
  messages: [{ role: 'user', content: userMsg }]
});

return [{ json: { requestBody } }];

const { tailored, pdfBase64 } = $input.first().json;
const company = (tailored.company || 'Company').replace(/[^a-zA-Z0-9]/g, '_');
const role = (tailored.role || 'Role').replace(/[^a-zA-Z0-9]/g, '_');
const filename = `Sridhar_Resume_${company}_${role}.pdf`;
const outputPath = `/app/output/${filename}`;

return [{
  json: { outputPath, filename, tailored },
  binary: {
    pdfFile: {
      data: pdfBase64,
      mimeType: 'application/pdf',
      fileName: filename
    }
  }
}];
